import React, {useState, useEffect } from "react";
import "./styles/EquiposPage.css";

const EquiposPage = () => {
    const [equipos, setEquipos] = useState([]);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        fetch("/data/equipos.json")
        .then((response) => {
            if (!response.ok) {
              throw new Error("Error al cargar los datos");
            }
            return response.json();
          })
          .then((data) => {
            setEquipos(data); // Guardar los datos en el estado
            setLoading(false); // Finalizar la carga
          })
          .catch((error) => {
            console.error("Error al cargar los equipos:", error);
            setLoading(false); // Finalizar la carga incluso si hay error
          });
    }, []);
    
    return (
        <div className="equipos-container">
            <h1>Lista de Equipos</h1>
            <div className="equipos-grid">
                {equipos.map((equipo) => (
                    <div key={equipo.id} className="equipo-card">
                        <img src={equipo.imagen} alt={equipo.nombre} className="equipo-imagen"/>
                        <h2>{equipo.nombre}</h2>
                        <p><strong>Liga:</strong>{equipo.liga}</p>
                        <div className="estadisticas">
                        <p><strong>Partidos Jugados:</strong> {equipo.estadisticas.partidosJugados}</p>
              <p><strong>Victorias:</strong> {equipo.estadisticas.victorias}</p>
              <p><strong>Empates:</strong> {equipo.estadisticas.empates}</p>
              <p><strong>Derrotas:</strong> {equipo.estadisticas.derrotas}</p>
              <p><strong>Goles a Favor:</strong> {equipo.estadisticas.golesFavor}</p>
              <p><strong>Goles en Contra:</strong> {equipo.estadisticas.golesContra}</p>
              </div>
            </div>
                ))}
            </div>
        </div>
    );
};

export default EquiposPage;
